  it('returns 400 for setValue when body is missing (no Content-Type header)', async () => {
    const res = await request(app)
      .post('/api/fibaro/devices/10/action/setValue')
      .set(AUTH)
      // intentionally no .send() — no body, no Content-Type
      ;
